import React, { useState } from 'react';

const CadastroTVpA = () => {
  const [form, setForm] = useState({
    campo1: '', campo2: '', campo3: '', campo4: '', campo5: '', campo6: '', campo7: '', campo8: ''
  });
  const [historico, setHistorico] = useState(() => {
    const salvo = localStorage.getItem('historicoTVpA');
    return salvo ? JSON.parse(salvo) : [];
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const nomeArquivo = `relatorio_tvpa_${new Date().toISOString().replace(/[:.]/g, '-')}.csv`;
    const conteudo = Object.values(form).join(';');
    const novoHistorico = [{ nome: nomeArquivo, conteudo, data: new Date().toLocaleString() }, ...historico];
    setHistorico(novoHistorico);
    localStorage.setItem('historicoTVpA', JSON.stringify(novoHistorico));
    setForm({ campo1: '', campo2: '', campo3: '', campo4: '', campo5: '', campo6: '', campo7: '', campo8: '' });
  };

  const handleExcluirHistorico = idx => {
    const novo = historico.filter((_, i) => i !== idx);
    setHistorico(novo);
    localStorage.setItem('historicoTVpA', JSON.stringify(novo));
  };

  return (
    <div>
      <h2>Novo Relatório TVpA</h2>
      <form onSubmit={handleSubmit}>
        {Object.keys(form).map((campo, idx) => (
          <React.Fragment key={campo}>
            <input name={campo} value={form[campo]} onChange={handleChange} placeholder={`Campo ${idx+1}`} />
            <br />
          </React.Fragment>
        ))}
        <button type="submit">Enviar</button>
      </form>
      {historico.length > 0 && (
        <div style={{marginTop:32}}>
          <h3>Histórico de Relatórios</h3>
          <table style={{width:'100%',maxWidth:600}}>
            <thead>
              <tr>
                <th>Nome</th>
                <th>Data</th>
                <th>Excluir</th>
              </tr>
            </thead>
            <tbody>
              {historico.map((h, idx) => (
                <tr key={h.nome}>
                  <td>{h.nome}</td>
                  <td>{h.data}</td>
                  <td>
                    <button onClick={() => handleExcluirHistorico(idx)} style={{background:'none',border:'none',color:'#d32f2f',fontSize:18,cursor:'pointer'}} title="Excluir do histórico" aria-label="Excluir do histórico">🗑️</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default CadastroTVpA;
